import React, { useState } from 'react';
import {
  Button,
  Checkbox,
  Input,
  Modal,
  Select,
  dispatchAppToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterCodeService } from '../../../services/system/masterCodeService';
import type {
  MasterCodeLegalEntityOptionDto,
  MasterCodeRegistrationDto,
  UpdateMasterCodeRegistrationDto,
} from '../../../services/system/masterCodeModels';
import {
  MASTER_CODE_FORMAT_OPTIONS,
  MASTER_CODE_SCOPE_LEGAL_ENTITY,
  MASTER_CODE_SCOPE_OPTIONS,
  SEQ_PADDING_MAX,
  SEQ_PADDING_MIN,
  SCOPE_MODE_LABELS,
  buildMasterCodePreview,
} from '../../../services/system/masterCodeModels';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import styles from '../../../styles/erpPage.module.css';

type FormErrors = Partial<Record<'format' | 'seqPadding' | 'legalEntityRootId', string>>;

function clampInteger(value: number, min: number, max: number): number {
  if (!Number.isFinite(value)) return min;
  const v = Math.trunc(value);
  return Math.max(min, Math.min(max, v));
}

export interface MasterCatalogCodeFormatTabProps {
  testIdPrefix?: string;
}

export const MasterCatalogCodeFormatTab: React.FC<MasterCatalogCodeFormatTabProps> = ({
  testIdPrefix = 'system-master-code-format',
}) => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<MasterCodeRegistrationDto[]>([]);
  const [legalEntityOptions, setLegalEntityOptions] = useState<MasterCodeLegalEntityOptionDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<MasterCodeRegistrationDto | null>(null);
  const [form, setForm] = useState<UpdateMasterCodeRegistrationDto>({
    format: 'PREFIX-NNNN',
    seqPadding: 6,
    minSequence: 1,
    maxSequence: 999999,
    scopeMode: 'Company',
    legalEntityRootId: null,
    useDepartmentPrefix: false,
  });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);

  const handleSearch = () => setSearch(searchDraft.trim());
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      Promise.all([masterCodeService.getList(), masterCodeService.getLegalEntityOptions()])
        .then(([data, legalOptions]) => {
          if (!cancelled) {
            setItems(data);
            setLegalEntityOptions(legalOptions);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: err instanceof Error ? err.message : 'Lỗi tải cấu hình mã danh mục',
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [reloadKey, dispatch]);

  const filtered = React.useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return items;
    return items.filter(
      r =>
        r.catalogKind.toLowerCase().includes(q)
        || r.prefix.toLowerCase().includes(q)
        || r.description.toLowerCase().includes(q)
        || r.format.toLowerCase().includes(q),
    );
  }, [items, search]);

  const openEdit = (row: MasterCodeRegistrationDto) => {
    setEditing(row);
    setForm({
      format: row.format,
      seqPadding: row.seqPadding,
      minSequence: row.minSequence,
      maxSequence: row.maxSequence,
      scopeMode: row.scopeMode,
      legalEntityRootId: row.legalEntityRootId ?? null,
      useDepartmentPrefix: row.useDepartmentPrefix,
    });
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.format?.trim()) next.format = 'Chọn định dạng mã';
    if (!Number.isFinite(form.seqPadding)) {
      next.seqPadding = 'Nhập số chữ số thứ tự';
    } else {
      const v = Math.trunc(form.seqPadding);
      if (v < SEQ_PADDING_MIN || v > SEQ_PADDING_MAX) {
        next.seqPadding = `Nhập số chữ số thứ tự (${SEQ_PADDING_MIN}–${SEQ_PADDING_MAX})`;
      }
    }
    if (form.scopeMode === MASTER_CODE_SCOPE_LEGAL_ENTITY && !form.legalEntityRootId) {
      next.legalEntityRootId = 'Chọn đơn vị pháp nhân';
    }
    return next;
  };

  const previewSeqPadding = React.useMemo(
    () => clampInteger(form.seqPadding, SEQ_PADDING_MIN, SEQ_PADDING_MAX),
    [form.seqPadding],
  );

  const previewExample = React.useMemo(() => {
    if (!editing) return '';
    return buildMasterCodePreview(
      editing.prefix,
      form.format,
      previewSeqPadding,
      form.minSequence,
      form.useDepartmentPrefix,
    );
  }, [editing, form.format, previewSeqPadding, form.minSequence, form.useDepartmentPrefix]);

  const handleSave = async () => {
    if (!editing) return;
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(testIdPrefix);
      return;
    }
    setSaving(true);
    try {
      await masterCodeService.update(editing.id, form);
      dispatchAppToast(dispatch, { message: 'Cập nhật định dạng mã thành công', type: 'success' });
      markClean();
      setModalOpen(false);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: err instanceof Error ? err.message : 'Lưu thất bại',
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  return (
    <>
      <p className={styles.subtitle} style={{ marginBottom: 12 }}>
        Cấu hình định dạng mã danh mục (nhân viên, vật tư, đối tượng, …). Prefix cố định — chỉ sửa format, phạm vi và padding.
      </p>

      <div className={styles.filtersBar} data-testid={`${testIdPrefix}-filters`}>
        <div className={styles.field} data-testid={`${testIdPrefix}-field-search`}>
          <Input
            placeholder="Tìm danh mục, prefix, mô tả..."
            value={searchDraft}
            onChange={e => setSearchDraft(e.target.value)}
            onKeyDown={e => {
              if (e.key === 'Enter') handleSearch();
            }}
          />
        </div>
        <ListSearchRefreshButtons testIdPrefix={testIdPrefix} onSearch={handleSearch} onRefresh={refresh} />
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}>
            <i className="fas fa-spinner fa-spin" /> Đang tải...
          </div>
        ) : filtered.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy cấu hình phù hợp' : 'Chưa có cấu hình — chạy migration MasterCodeRegistrations'}</p>
          </div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Danh mục</th>
                  <th>Prefix</th>
                  <th>Mô tả</th>
                  <th>Phạm vi</th>
                  <th>Định dạng</th>
                  <th>Ví dụ</th>
                  <th>Số chữ số</th>
                  <th className={styles.colActions} />
                </tr>
              </thead>
              <tbody>
                {filtered.map(r => (
                  <tr key={r.id}>
                    <td><code>{r.catalogKind}</code></td>
                    <td><code>{r.prefix}</code></td>
                    <td>{r.description}</td>
                    <td>{SCOPE_MODE_LABELS[r.scopeMode] ?? r.scopeMode}</td>
                    <td><code>{r.format}</code></td>
                    <td><code>{r.exampleCode}</code></td>
                    <td>{r.seqPadding}</td>
                    <td className={styles.colActions}>
                      <button
                        type="button"
                        className={styles.actionBtn}
                        onClick={() => openEdit(r)}
                        title="Sửa định dạng"
                        data-testid={`${testIdPrefix}-edit-${r.catalogKind}`}
                      >
                        <i className="fas fa-edit" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      <Modal isOpen={modalOpen} onClose={closeFormModal} title="Sửa định dạng mã danh mục">
        <div data-testid={`${testIdPrefix}-modal-form`}>
          {editing && (
            <>
              <div className={styles.formGrid}>
                <div className={styles.field}>
                  <Input label="Prefix (không đổi)" value={editing.prefix} disabled fullWidth />
                </div>
                <div className={styles.field}>
                  <Input label="Danh mục" value={editing.catalogKind} disabled fullWidth />
                </div>
                <div className={styles.field} style={{ gridColumn: '1 / -1' }}>
                  <Input label="Mô tả" value={editing.description} disabled fullWidth />
                </div>
                <div
                  className={styles.field}
                  style={{ gridColumn: '1 / -1' }}
                  data-testid={`${testIdPrefix}-field-format`}
                >
                  <Select
                    label="Định dạng"
                    required
                    value={form.format}
                    onChange={e => {
                      markDirty();
                      setErrors(prev => ({ ...prev, format: undefined }));
                      setForm(f => ({ ...f, format: e.target.value }));
                    }}
                    options={[...MASTER_CODE_FORMAT_OPTIONS]}
                    error={errors.format}
                    fullWidth
                  />
                </div>
                <div className={styles.field} data-testid={`${testIdPrefix}-field-seqPadding`}>
                  <Input
                    label="Số chữ số thứ tự"
                    type="number"
                    required
                    value={String(form.seqPadding ?? '')}
                    onChange={e => {
                      markDirty();
                      setErrors(prev => ({ ...prev, seqPadding: undefined }));
                      const raw = e.target.value;
                      const next = raw === '' ? NaN : Number(raw);
                      setForm(f => ({ ...f, seqPadding: next }));
                    }}
                    error={errors.seqPadding}
                    fullWidth
                  />
                </div>
                <div className={styles.field} data-testid={`${testIdPrefix}-field-example-preview`}>
                  <Input label="Ví dụ sau lưu" value={previewExample} disabled fullWidth />
                </div>
                <div
                  className={styles.field}
                  style={{ gridColumn: '1 / -1' }}
                  data-testid={`${testIdPrefix}-field-scopeMode`}
                >
                  <Select
                    label="Phạm vi sinh mã"
                    value={form.scopeMode}
                    onChange={e => {
                      markDirty();
                      const scopeMode = e.target.value;
                      setForm(f => ({
                        ...f,
                        scopeMode,
                        legalEntityRootId:
                          scopeMode === MASTER_CODE_SCOPE_LEGAL_ENTITY ? f.legalEntityRootId : null,
                      }));
                    }}
                    options={[...MASTER_CODE_SCOPE_OPTIONS]}
                    fullWidth
                  />
                </div>
                {form.scopeMode === MASTER_CODE_SCOPE_LEGAL_ENTITY ? (
                  <div
                    className={styles.field}
                    style={{ gridColumn: '1 / -1' }}
                    data-testid={`${testIdPrefix}-field-legalEntityRootId`}
                  >
                    <Select
                      label="Đơn vị pháp nhân"
                      required
                      value={form.legalEntityRootId ?? ''}
                      onChange={e => {
                        markDirty();
                        setErrors(prev => ({ ...prev, legalEntityRootId: undefined }));
                        setForm(f => ({
                          ...f,
                          legalEntityRootId: e.target.value || null,
                        }));
                      }}
                      options={[
                        { value: '', label: 'Chọn đơn vị pháp nhân' },
                        ...legalEntityOptions.map(o => ({
                          value: o.id,
                          label: `${o.code} — ${o.name}`,
                        })),
                      ]}
                      error={errors.legalEntityRootId}
                      fullWidth
                    />
                  </div>
                ) : null}
                <div
                  className={styles.field}
                  style={{ gridColumn: '1 / -1' }}
                  data-testid={`${testIdPrefix}-field-useDepartmentPrefix`}
                >
                  <Checkbox
                    label="Thêm mã phòng ban vào prefix (EMP-{PB}-######)"
                    checked={form.useDepartmentPrefix}
                    onChange={e => {
                      markDirty();
                      setForm(f => ({ ...f, useDepartmentPrefix: e.target.checked }));
                    }}
                  />
                </div>
              </div>
              <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 16 }}>
                <Button variant="secondary" onClick={closeFormModal} data-testid={`${testIdPrefix}-cancel-btn`}>
                  Hủy
                </Button>
                <Button
                  variant="primary"
                  onClick={handleSave}
                  disabled={saving}
                  data-testid={`${testIdPrefix}-save-btn`}
                >
                  {saving ? 'Đang lưu...' : 'Lưu'}
                </Button>
              </div>
            </>
          )}
        </div>
      </Modal>
      <LeaveConfirmModal {...leaveConfirmModalProps} />
    </>
  );
};

export default MasterCatalogCodeFormatTab;
