import React from 'react';
import { MasterCatalogCodeFormatTab } from './MasterCatalogCodeFormatTab';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'system-master-code-setup';

const MasterCatalogCodeSetupPage: React.FC = () => (
  <div className={styles.page} data-testid={TEST_ID}>
    <div className={styles.pageHeader}>
      <div className={styles.titleBlock}>
        <h1 className={styles.title}>
          <i className="fas fa-barcode" /> Thiết lập mã danh mục
        </h1>
        <p className={styles.subtitle}>
          Định dạng mã tự sinh cho danh mục master (nhân viên, vật tư, kho, …) — phạm vi tenant/pháp nhân và prefix phòng ban.
        </p>
      </div>
    </div>
    <MasterCatalogCodeFormatTab testIdPrefix={`${TEST_ID}-format`} />
  </div>
);

export default MasterCatalogCodeSetupPage;
